import React from 'react';

// Simple Button component
const Button = ({ children, className, onClick }) => (
  <button 
    className={className}
    onClick={onClick}
    style={{
      backgroundColor: '#1c3ff9',
      color: 'white',
      padding: '12px 24px',
      borderRadius: '25px',
      border: 'none',
      cursor: 'pointer',
      fontSize: '16px',
      fontWeight: 'bold'
    }}
  >
    {children}
  </button>
);

function App() {
  console.log("App component is rendering!");

  return (
    <div style={{ 
      minHeight: '100vh', 
      backgroundColor: 'white',
      padding: '50px',
      textAlign: 'center',
      fontFamily: 'Arial, sans-serif'
    }}>
      <div style={{ maxWidth: '800px', margin: '0 auto' }}>
        <h1 style={{ 
          color: '#1c3ff9', 
          fontSize: '48px', 
          marginBottom: '20px',
          fontWeight: 'bold'
        }}>
          KAPTA Media
        </h1>
        <p style={{ 
          color: '#666', 
          fontSize: '18px', 
          marginBottom: '30px',
          lineHeight: '1.6'
        }}>
          Votre concurrent est N°1. Ce n'est pas une fatalité.
        </p>
        <Button onClick={() => alert('Ça marche !')}>
          SÉCURISER MA ZONE
        </Button>
      </div>
    </div>
  );
}

export default App;
